import re
import warnings
from typing import Union, List, Set, Optional, Callable, Any, Tuple
from pathlib import Path


class ParameterMatcher:
    """
    Match LLM-generated parameter names against data dictionary.
    
    Uses 2-tier strategy:
    1. Normalized exact match (fast)
    2. Fuzzy string matching (accurate)
    
    Examples:
        >>> whitelist = {'range', 'cruise speed', 'weight', 'power'}
        >>> matcher = ParameterMatcher(whitelist, fuzzy_threshold=0.85)
        >>> 
        >>> # Test matches
        >>> is_match, matched_entry, confidence = matcher.match("operational range")
        >>> print(f"Matched: {matched_entry} ({confidence:.2f})")
        >>> # Matched: range (0.89)
        >>> 
        >>> is_match, matched_entry, confidence = matcher.match("avg cruise speed")
        >>> print(f"Matched: {matched_entry} ({confidence:.2f})")
        >>> # Matched: cruise speed (0.93)
    """
    
    def __init__(
        self,
        whitelist: Set[str],
        fuzzy_threshold: float = 0.85,
        case_sensitive: bool = False,
    ):
        """
        Initialize parameter matcher.
        
        Args:
            whitelist: Set of allowed parameter names
            fuzzy_threshold: Minimum similarity for fuzzy matching (0-1)
            case_sensitive: Whether to match case-sensitively
        """
        self.whitelist = whitelist
        self.fuzzy_threshold = fuzzy_threshold
        self.case_sensitive = case_sensitive
        
        # Create normalized mapping: normalized_name -> original_name
        self.normalized_whitelist = {}
        for name in whitelist:
            normalized = self._normalize(name)
            self.normalized_whitelist[normalized] = name
    
    def _normalize(self, text: str) -> str:
        """
        Normalize parameter name for comparison.
        
        Steps:
        1. Lowercase (if not case_sensitive)
        2. Remove content in parentheses (units)
        3. Remove content in brackets
        4. Expand common abbreviations
        5. Remove common modifiers
        6. Remove punctuation except hyphens
        7. Normalize whitespace
        
        Args:
            text: Parameter name to normalize
            
        Returns:
            Normalized text
        """
        # Lowercase
        if not self.case_sensitive:
            text = text.lower()
        
        # Remove content in parentheses (units)
        text = re.sub(r'\([^)]*\)', '', text)
        
        # Remove content in brackets
        text = re.sub(r'\[[^\]]*\]', '', text)
        
        # Expand common abbreviations
        abbreviations = {
            r'\bavg\b': 'average',
            r'\bmax\b': 'maximum',
            r'\bmin\b': 'minimum',
            r'\btemp\b': 'temperature',
            r'\bvel\b': 'velocity',
            r'\balt\b': 'altitude',
            r'\bcap\b': 'capacity',
            r'\bfreq\b': 'frequency',
            r'\boper\b': 'operational',
            r'\bpwr\b': 'power',
            r'\bwt\b': 'weight',
            r'\bht\b': 'height',
            r'\blen\b': 'length',
            r'\bdia\b': 'diameter',
            r'\bvol\b': 'volume',
        }
        for abbr, full in abbreviations.items():
            text = re.sub(abbr, full, text)
        
        # Remove common modifiers (that don't change core meaning)
        modifiers = [
            'operational', 'maximum', 'minimum', 'average',
            'total', 'net', 'gross', 'effective', 'actual',
            'required', 'threshold', 'objective', 'nominal',
            'typical', 'standard', 'normal', 'peak',
            'output', 'input', 'rated', 'measured', 'estimated',
        ]
        for mod in modifiers:
            # Use word boundaries to avoid partial matches
            text = re.sub(r'\b' + re.escape(mod) + r'\b', '', text, flags=re.IGNORECASE if not self.case_sensitive else 0)
        
        # Remove punctuation except hyphens and underscores
        text = re.sub(r'[^\w\s\-]', '', text)
        
        # Normalize whitespace
        text = ' '.join(text.split())
        
        return text.strip()
    
    def match(self, param_name: str) -> Tuple[bool, Optional[str], float]:
        """
        Check if parameter name matches whitelist.
        
        Args:
            param_name: Parameter name to check
            
        Returns:
            Tuple of (is_match, matched_entry, confidence_score)
            - is_match: True if parameter matches whitelist
            - matched_entry: The original whitelist entry that was matched (None if no match)
            - confidence_score: Confidence score 0-1 (1.0 = exact match)
        """
        # Tier 1: Normalized exact match
        normalized = self._normalize(param_name)
        if normalized in self.normalized_whitelist:
            original = self.normalized_whitelist[normalized]
            return (True, original, 1.0)
        
        # Tier 2: Fuzzy string matching
        try:
            from rapidfuzz import fuzz, process
            
            # Find best fuzzy match against normalized whitelist
            result = process.extractOne(
                normalized,
                self.normalized_whitelist.keys(),
                scorer=fuzz.ratio
            )
            
            if result and result[1] >= self.fuzzy_threshold * 100:
                matched_normalized = result[0]
                original = self.normalized_whitelist[matched_normalized]
                confidence = result[1] / 100.0
                return (True, original, confidence)
                
        except ImportError:
            # rapidfuzz not available, skip fuzzy matching
            pass
        
        # No match found
        return (False, None, 0.0)


def load_parameter_whitelist(
    filepath: str,
    column: Optional[str] = None,
    case_sensitive: bool = False,
    normalize_fn: Optional[Callable[[str], str]] = None
) -> Set[str]:
    """
    Load a whitelist of parameter names from Excel, CSV, or text file.
    
    Args:
        filepath: Path to Excel (.xlsx, .xls), CSV (.csv), or text file (.txt, .md)
        column: Column name for Excel/CSV (uses first column if None)
        case_sensitive: If False, converts all names to lowercase
        normalize_fn: Optional function to normalize names
        
    Returns:
        Set of parameter names
        
    Examples:
        >>> # From Excel
        >>> whitelist = load_parameter_whitelist('data_dict.xlsx', column='Parameter Name')
        >>> 
        >>> # From CSV
        >>> whitelist = load_parameter_whitelist('params.csv')
        >>> 
        >>> # From text file (one parameter per line)
        >>> whitelist = load_parameter_whitelist('params.txt')
    """
    filepath = Path(filepath)
    
    if not filepath.exists():
        raise FileNotFoundError(f"File not found: {filepath}")
    
    # Load based on file extension
    if filepath.suffix in ['.xlsx', '.xls']:
        try:
            import pandas as pd
        except ImportError:
            raise ImportError("pandas is required to read Excel files. Install with: pip install pandas openpyxl")
        
        df = pd.read_excel(filepath)
        col = column if column else df.columns[0]
        if col not in df.columns:
            raise ValueError(f"Column '{col}' not found in {filepath}. Available: {list(df.columns)}")
        names = df[col].dropna().astype(str).tolist()
        
    elif filepath.suffix == '.csv':
        try:
            import pandas as pd
        except ImportError:
            raise ImportError("pandas is required to read CSV files. Install with: pip install pandas")
        
        df = pd.read_csv(filepath)
        col = column if column else df.columns[0]
        if col not in df.columns:
            raise ValueError(f"Column '{col}' not found in {filepath}. Available: {list(df.columns)}")
        names = df[col].dropna().astype(str).tolist()
        
    elif filepath.suffix in ['.txt', '.md']:
        with open(filepath, 'r', encoding='utf-8') as f:
            names = [line.strip() for line in f if line.strip()]
    else:
        raise ValueError(f"Unsupported file type: {filepath.suffix}. Supported: .xlsx, .xls, .csv, .txt, .md")
    
    # Apply normalization
    if not case_sensitive:
        names = [n.lower() for n in names]
    
    if normalize_fn:
        names = [normalize_fn(n) for n in names]
    
    return set(names)


def create_parameter_filter(
    whitelist: Union[Set[str], List[str], str],
    field_name: str = 'name',
    fuzzy_threshold: float = 0.85,
    case_sensitive: bool = False,
    normalize: bool = True,
) -> Callable[[Any], bool]:
    """
    Create a filter function for parameters based on a whitelist.
    
    Handles LLM-generated parameter names that don't exactly match the dictionary.
    Uses text normalization and fuzzy string matching.
    
    Args:
        whitelist: Set/list of allowed values or filepath to load from
        field_name: Field to check in each parameter dict/object
        fuzzy_threshold: Minimum similarity for fuzzy matching (0-1)
        case_sensitive: Whether to match case-sensitively
        normalize: Apply text normalization (remove units, expand abbreviations, etc.)
        
    Returns:
        Callable[[Parameter], bool] that can be used as filter_fn
        
    Examples:
        >>> # From Python set
        >>> whitelist = {'range', 'cruise speed', 'weight', 'power'}
        >>> filter_fn = create_parameter_filter(whitelist, fuzzy_threshold=0.85)
        >>> 
        >>> # From Excel file
        >>> filter_fn = create_parameter_filter('data_dict.xlsx', fuzzy_threshold=0.85)
        >>> 
        >>> # Use in extraction
        >>> result = extractor.extract_parameters(
        ...     fpath="document.pdf",
        ...     parameter_whitelist=whitelist,
        ...     matching_strategy='fuzzy'
        ... )
    """
    # Load whitelist if it's a filepath
    if isinstance(whitelist, str):
        whitelist = load_parameter_whitelist(whitelist, case_sensitive=case_sensitive)
    else:
        whitelist = set(whitelist)
        if not case_sensitive:
            whitelist = {item.lower() for item in whitelist}
    
    # Create matcher
    if normalize:
        matcher = ParameterMatcher(
            whitelist=whitelist,
            fuzzy_threshold=fuzzy_threshold,
            case_sensitive=case_sensitive
        )
        
        def filter_fn(item):
            # Get the field value
            if isinstance(item, dict):
                value = item.get(field_name, '')
            else:
                value = getattr(item, field_name, '')
            
            # Check if it matches
            is_match, matched_entry, confidence = matcher.match(value)
            return is_match
    else:
        # Simple string matching without normalization
        def filter_fn(item):
            # Get the field value
            if isinstance(item, dict):
                value = item.get(field_name, '')
            else:
                value = getattr(item, field_name, '')
            
            if not case_sensitive:
                value = value.lower()
            
            return value in whitelist
    
    return filter_fn


def create_regex_filter(
    patterns: List[str],
    field_name: str = 'name',
    match_any: bool = True,
    case_sensitive: bool = False,
) -> Callable[[Any], bool]:
    """
    Create filter based on regex patterns.
    
    Args:
        patterns: List of regex patterns
        field_name: Field to check in each item
        match_any: If True, match any pattern (OR logic). If False, match all (AND logic)
        case_sensitive: Whether patterns are case-sensitive
        
    Returns:
        Filter function
        
    Examples:
        >>> # Match parameters containing "speed" or "velocity"
        >>> filter_fn = create_regex_filter([r'speed', r'velocity'], match_any=True)
        >>> 
        >>> # Match parameters that are distances (end with distance units)
        >>> filter_fn = create_regex_filter([r'\b(nm|km|mi|miles?)\b'], match_any=True)
    """
    flags = 0 if case_sensitive else re.IGNORECASE
    compiled_patterns = [re.compile(p, flags) for p in patterns]
    
    def filter_fn(item):
        if isinstance(item, dict):
            value = item.get(field_name, '')
        else:
            value = getattr(item, field_name, '')
        
        if match_any:
            # OR logic - match any pattern
            return any(pattern.search(value) for pattern in compiled_patterns)
        else:
            # AND logic - match all patterns
            return all(pattern.search(value) for pattern in compiled_patterns)
    
    return filter_fn


def create_value_range_filter(
    min_value: Optional[float] = None,
    max_value: Optional[float] = None,
    unit_whitelist: Optional[Set[str]] = None,
    case_sensitive: bool = False,
) -> Callable[[Any], bool]:
    """
    Filter parameters by value range and/or unit.
    
    Args:
        min_value: Minimum allowed value (inclusive)
        max_value: Maximum allowed value (inclusive)
        unit_whitelist: Set of allowed units (None = allow all)
        case_sensitive: Whether unit matching is case-sensitive
        
    Returns:
        Filter function
        
    Examples:
        >>> # Only positive values
        >>> filter_fn = create_value_range_filter(min_value=0.001)
        >>> 
        >>> # Values between 0 and 1000
        >>> filter_fn = create_value_range_filter(min_value=0, max_value=1000)
        >>> 
        >>> # Only speed units
        >>> filter_fn = create_value_range_filter(
        ...     unit_whitelist={'mph', 'knots', 'kts', 'km/h'}
        ... )
        >>> 
        >>> # Combine: positive speeds only
        >>> filter_fn = create_value_range_filter(
        ...     min_value=0,
        ...     unit_whitelist={'mph', 'knots', 'kts', 'km/h'}
        ... )
    """
    # Normalize unit whitelist if provided
    if unit_whitelist is not None and not case_sensitive:
        unit_whitelist = {u.lower() for u in unit_whitelist}
    
    def filter_fn(item):
        # Check value range
        if min_value is not None or max_value is not None:
            if isinstance(item, dict):
                value = item.get('value')
            else:
                value = getattr(item, 'value', None)
            
            if value is None:
                return False
            
            if min_value is not None and value < min_value:
                return False
            if max_value is not None and value > max_value:
                return False
        
        # Check unit whitelist
        if unit_whitelist is not None:
            if isinstance(item, dict):
                unit = item.get('unit', '')
            else:
                unit = getattr(item, 'unit', '')
            
            if not case_sensitive:
                unit = unit.lower()
            
            if unit not in unit_whitelist:
                return False
        
        return True
    
    return filter_fn


def combine_filters(
    *filters: Callable[[Any], bool],
    logic: str = 'AND'
) -> Callable[[Any], bool]:
    """
    Combine multiple filter functions with AND/OR logic.
    
    Args:
        *filters: Variable number of filter functions
        logic: 'AND' or 'OR' (case-insensitive)
        
    Returns:
        Combined filter function
        
    Examples:
        >>> # Parameter must match whitelist AND have positive value
        >>> name_filter = create_parameter_filter(whitelist)
        >>> value_filter = create_value_range_filter(min_value=0)
        >>> combined = combine_filters(name_filter, value_filter, logic='AND')
        >>> 
        >>> # Parameter must match whitelist OR match regex pattern
        >>> name_filter = create_parameter_filter(whitelist)
        >>> regex_filter = create_regex_filter([r'critical'])
        >>> combined = combine_filters(name_filter, regex_filter, logic='OR')
    """
    if logic.upper() == 'AND':
        def combined_filter(item):
            return all(f(item) for f in filters)
    elif logic.upper() == 'OR':
        def combined_filter(item):
            return any(f(item) for f in filters)
    else:
        raise ValueError("logic must be 'AND' or 'OR'")
    
    return combined_filter
